# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Prevent insecure universal link handling.
# Category: insecure_universal_links

import UIKit
import Foundation

class UniversalLinkHandler: NSObject, WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            return decisionHandler(.allow)
        }
        
        // Check if the URL is a password reset link
        if url.absoluteString.hasPrefix("https://myapp.com/reset-password") {
            // Parse the token from the URL
            let token = url.queryParameters["token"] ?? ""
            
            // Navigate to the password reset screen with the token
            let storyboard = UIStoryboard(name: "PasswordReset", bundle: nil)
            let vc = storyboard.instantiateInitialViewController() as! PasswordResetViewController
            vc.token = token
            navigationController?.pushViewController(vc, animated: true)
            
            return decisionHandler(.cancel)
        }
        
        return decisionHandler(.allow)
    }
}